// Returns a random paragraph for the requested language. Adding a new
// language or category later only requires extending PARAGRAPHS above.
export function getRandomParagraph(language) {
  const list = PARAGRAPHS[language] || PARAGRAPHS.english;
  const index = Math.floor(Math.random() * list.length);
  return list[index];
}

// Returns the count of available paragraphs for a language, used to build
// the "which passage" picker on the Home page.
export function getParagraphCount(language) {
  return (PARAGRAPHS[language] || PARAGRAPHS.english).length;
}

// Returns a specific paragraph by index, falling back to a random one if
// the index is missing or out of range.
export function getParagraphByIndex(language, index) {
  const list = PARAGRAPHS[language] || PARAGRAPHS.english;
  if (index === null || index === undefined || index < 0 || index >= list.length) {
    return getRandomParagraph(language);
  }
  return list[index];
}
